package network;
import java.io.*; import java.net.Socket; import java.nio.charset.StandardCharsets; import java.nio.file.*; import java.time.LocalDateTime;
public class ClientHandler extends Thread { private final Socket socket; public ClientHandler(Socket socket){this.socket=socket;} public void run(){ try(BufferedReader in=new BufferedReader(new InputStreamReader(socket.getInputStream(),StandardCharsets.UTF_8))){ String line; while((line=in.readLine())!=null) save(line); }catch(IOException ignored){} } private synchronized void save(String msg) throws IOException{ Files.createDirectories(Paths.get("server_data")); Files.writeString(Paths.get("server_data","server_log.txt"), LocalDateTime.now()+"|"+msg+System.lineSeparator(), StandardCharsets.UTF_8, StandardOpenOption.CREATE, StandardOpenOption.APPEND); updateSummary(msg); } private void updateSummary(String msg) throws IOException{ String[] p=msg.split("\\|"); if(p.length>=6 && p[0].equals("SALE")){ String line=p[1]+","+p[2]+","+p[3]+","+p[4]+","+p[5]+System.lineSeparator(); Files.writeString(Paths.get("server_data","sales_summary.txt"),line,StandardCharsets.UTF_8,StandardOpenOption.CREATE,StandardOpenOption.APPEND);} if(p.length>=4 && (p[0].equals("STOCK")||p[0].equals("LOW_STOCK"))) Files.writeString(Paths.get("server_data","stock_status.txt"),msg+System.lineSeparator(),StandardCharsets.UTF_8,StandardOpenOption.CREATE,StandardOpenOption.APPEND); } }
